const results = [];

for (const item of $input.all()) {

const memo = item.json;

const services = Array.isArray(memo.services_supported)
  ? memo.services_supported.join(", ")
  : memo.services_supported || "Not specified";

const emergencies = Array.isArray(memo.emergency_definition)
  ? memo.emergency_definition.join(", ")
  : memo.emergency_definition || "Not specified";

const agentSpec = {

  agent_name: `${memo.company_name || "Service Company"} Voice Assistant`,

  voice_style: "professional-friendly",

  version: "v1",

  key_variables: {
    timezone: memo.business_hours?.timezone || null,
    business_hours: memo.business_hours || null,
    office_address: memo.office_address || null,
    emergency_routing: memo.emergency_routing_rules || null
  },

  system_prompt: `
You are the phone assistant for ${memo.company_name || "this company"}.

BUSINESS HOURS
${JSON.stringify(memo.business_hours || {})}

SERVICES SUPPORTED
${services}

EMERGENCY DEFINITIONS
${emergencies}

OFFICE HOURS FLOW
1. Greet the caller professionally.
2. Ask the reason for the call.
3. Collect caller name and phone number.
4. Determine if the issue qualifies as an emergency.
5. If emergency → immediately transfer according to routing rules.
6. If non-emergency → collect contact info for scheduling.
7. Confirm next steps with the caller.
8. Ask if they need anything else.
9. End call politely.

AFTER HOURS FLOW
1. Greet caller.
2. Ask if the issue is an emergency.
3. Emergency definition includes:
${emergencies}

4. If emergency:
   - collect name
   - phone number
   - service address
   - attempt transfer using escalation rules.

5. If transfer fails:
   - reassure caller help is on the way
   - confirm phone number
   - inform them someone will call shortly.

6. If non-emergency:
   - collect contact information
   - inform caller that dispatch will contact them next business day.

Never mention tools, APIs, or internal systems to the caller.
`,

  tool_invocation_placeholders: [
    {
      name: "transfer_call",
      purpose: "Transfer caller to appropriate contact"
    },
    {
      name: "create_callback_request",
      purpose: "Log a callback request for dispatch"
    },
    {
      name: "lookup_customer",
      purpose: "Retrieve existing customer information"
    }
  ],

  call_transfer_protocol: {
    retry_limit: memo.call_transfer_rules?.retry_limit || 2,
    escalation_order: memo.emergency_routing_rules || null
  },

  fallback_protocol: memo.call_transfer_rules?.failed_transfer_script ||
    "If transfer fails, reassure the caller that someone will call them back shortly.",

  metadata: {
    generated_from: "demo_call",
    generated_at: new Date().toISOString()
  }
};

results.push({ json: agentSpec });

}

return results;

const results = [];

for (const item of $input.all()) {
  let raw = item.json.content.parts[0].text;
  raw = raw.replace(/```json/g, "").replace(/```/g, "").trim();

  const memo = JSON.parse(raw);

  const companySlug = (memo.company_name || "unknown-company")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-");

  const accountId = "ACC-" + companySlug + "-" + Date.now();

  memo.account_id = accountId;

  results.push({ json: memo });
}

return results;

const items = $input.all();

const oldMemo = items[0].json;
const newMemo = items[1].json;

const updatedMemo = {...oldMemo};
const changes = {};

for (const key in newMemo) {

  const oldValue = oldMemo[key];
  const newValue = newMemo[key];

  if (newValue === null || newValue === undefined) continue;

  if (JSON.stringify(oldValue) !== JSON.stringify(newValue)) {

    changes[key] = {
      old: oldValue || null,
      new: newValue,
      reason: "Updated during onboarding call",
      timestamp: new Date().toISOString()
    };

    updatedMemo[key] = newValue;
  }
}

return [{
  json: {
    account_id: oldMemo.account_id,
    updatedMemo,
    changes
  }
}];
